"""Тесты этапа Extract и вспомогательной статистики контента."""from pathlib import Pathimport pytestfrom src.modules.file_discovery.models import DiscoveredDocumentfrom src.modules.file_extract import build_extract_configfrom src.modules.file_extract.models import (    CONTENT_TYPE_IMAGE,    CONTENT_TYPE_MARKDOWN,    CONTENT_TYPE_TEXT,    ExtractedDocument,    ExtractedDocumentContent,    SEMANTIC_TYPE_DOCUMENT_FRAGMENT,)from src.modules.project.project_config import ProjectConfigfrom src.modules.project_pipeline.stages.extract.stage import extract_content_stats@pytest.fixturedef extract_config(tmp_path: Path):    cfg = ProjectConfig.create_default(tmp_path)    return build_extract_config(tmp_path, cfg.extract, cfg.paths.cache_extract)def test_extract_content_stats_counts_fragments_images_markdown(    tmp_path: Path, extract_config) -> None:    doc = ExtractedDocument(        source=DiscoveredDocument(            path=str(tmp_path / "f.pdf"),            folder=".",            filename="f",            extension=".pdf",            mime_type="application/pdf",            hash=None,        ),        config=extract_config,        extract_hash="h",        content=[            ExtractedDocumentContent(                content_type=CONTENT_TYPE_TEXT,                semantic_type=SEMANTIC_TYPE_DOCUMENT_FRAGMENT,                path=None,                mime_type="text/plain",                value="a",            ),            ExtractedDocumentContent(                content_type=CONTENT_TYPE_IMAGE,                semantic_type=SEMANTIC_TYPE_DOCUMENT_FRAGMENT,                path="/i.png",                mime_type="image/png",            ),            ExtractedDocumentContent(                content_type=CONTENT_TYPE_MARKDOWN,                semantic_type=SEMANTIC_TYPE_DOCUMENT_FRAGMENT,                path=None,                mime_type="text/markdown",                value="# m",            ),        ],    )    assert extract_content_stats([doc, None]) == (3, 1, 1)